// v28: Store seen company keys from BOTH Seen Opportunities and Funding Alerts
const staticData = $getWorkflowStaticData("global");
const seenKeys = new Set();
const items = $input.all();

for (const item of items) {
  const key = item.json.Key;
  if (key && key.startsWith("company:")) {
    seenKeys.add(key);
    continue;
  }
  const companyName = item.json["Company Name"];
  if (companyName) {
    const normalizedKey = "company:" + companyName.toLowerCase().replace(/[^a-z0-9]/g, "");
    seenKeys.add(normalizedKey);
  }
}

staticData.seenCompanyKeys = Array.from(seenKeys);
console.log(`v28: Stored ${seenKeys.size} seen company keys`);
return [{ json: { seenKeysLoaded: true, count: seenKeys.size } }];

