for (const item of items) {
  if (item.json._empty) continue;
  const name = item.json["Company Name"] || "";
  if (!name || name.length < 2) continue;

  const localKey = name.toLowerCase().replace(/[^a-z0-9]/g, "");
  if (localSeen.has(localKey)) { skipped++; continue; }
  localSeen.add(localKey);

  const dedupKey = "company:" + localKey;
  if (seenKeys.has(dedupKey)) { skipped++; continue; }

  newCompanies.push(item);
}

console.log(`v28 Filter: ${skipped} already seen, ${newCompanies.length} NEW`);
if (newCompanies.length === 0) {
  return [{ json: { _empty: true, _message: "All companies already processed", skipped } }];
}
return newCompanies;
